Here's the complete implementation of the functions using the Hexi library:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket packet;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read packet_id
    stream.get(packet.packet_id);

    // Read username with length prefix
    stream.get(hexi::prefixed(packet.username));

    // Read score count and then the scores vector using container adaptor
    uint32_t score_count;
    stream.get(score_count);
    packet.scores.resize(score_count);
    stream.get(hexi::container(packet.scores));

    // Read metadata as null-terminated string (zero-copy view first, then copy to string)
    std::string_view metadata_view;
    stream.get(hexi::null_terminated(metadata_view));
    packet.metadata = std::string(metadata_view);

    // Skip any remaining padding bytes
    if (adaptor.tell_read() < adaptor.size()) {
        stream.skip(adaptor.size() - adaptor.tell_read());
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use span() for packet_id (zero-copy view of first 4 bytes)
    std::span<const uint32_t> packet_id_span = std::span<const uint32_t>(
        reinterpret_cast<const uint32_t*>(buffer.data()), 1);
    info.packet_id = packet_id_span[0];

    // Skip past the packet_id (4 bytes) since we already read it via span
    stream.skip(sizeof(uint32_t));

    // Read username using prefixed adaptor to get string_view (zero-copy)
    stream.get(hexi::prefixed(info.username));

    // Skip the scores vector: read count, then skip the data
    uint32_t score_count;
    stream.get(score_count);
    stream.skip(score_count * sizeof(uint32_t));

    return info;
}
```

Key points about the implementation:

1. **deserialize_packet**:
   - Uses `hexi::prefixed` for the username to handle length-prefixed strings
   - Uses `hexi::container` for the scores vector after reading the count
   - Uses `hexi::null_terminated` for zero-copy metadata reading, then copies to `std::string`
   - Skips any remaining padding bytes using the adaptor's position information

2. **extract_packet_info**:
   - Uses `std::span` directly for zero-copy access to the packet_id
   - Uses `hexi::prefixed` to get a `std::string_view` of the username (zero-copy)
   - Reads the score count but skips the actual score data using `stream.skip()`
   - Only extracts the required fields without fully deserializing the entire packet

Both functions use Hexi's streaming interface with buffer adaptors to efficiently handle the binary data with proper zero-copy operations where possible.

