```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
    uint32_t footer;
};

MessageHeader read_header_and_skip_body(const std::span<const uint8_t> buffer) {
    // Convert the uint8_t span to std::byte span for Hexi compatibility
    std::span<const std::byte> byte_span(reinterpret_cast<const std::byte*>(buffer.data()), buffer.size());

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(byte_span);
    hexi::binary_stream stream(adaptor);

    // Read message_type (uint16_t)
    uint16_t message_type = stream.get<uint16_t>();

    // Read body_length (uint32_t)  
    uint32_t body_length = stream.get<uint32_t>();

    // Skip the body_data of body_length bytes
    stream.skip(body_length);

    // Read footer (uint32_t)
    uint32_t footer = stream.get<uint32_t>();

    return MessageHeader{message_type, body_length, footer};
}
```

