#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    hexi::buffer_adaptor adaptor(const_cast<std::vector<uint8_t>&>(buffer));
    return reinterpret_cast<const uint8_t*>(adaptor.read_data());
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    return reinterpret_cast<uint8_t*>(adaptor.write_data());
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    hexi::buffer_adaptor adaptor(const_cast<std::vector<uint8_t>&>(buffer));

    BufferInfo info;
    info.readable_size = adaptor.size();  // Number of bytes available to read
    info.free_space = buffer.capacity() - buffer.size();  // Available space for writing

    return info;
}
```

However, based on the Hexi library patterns I see in the code fragments, a more accurate implementation that properly uses the buffer adaptor's interface would be:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor to access the read pointer
    hexi::buffer_adaptor adaptor(const_cast<std::vector<uint8_t>&>(buffer));
    // The adaptor manages the read position internally
    return buffer.data() + adaptor.read_offset();
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor to access the write pointer  
    hexi::buffer_adaptor adaptor(buffer);
    // The adaptor manages the write position internally
    return buffer.data() + adaptor.write_offset();
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    hexi::buffer_adaptor adaptor(const_cast<std::vector<uint8_t>&>(buffer));

    BufferInfo info;
    info.readable_size = adaptor.size();  // Bytes available to read
    info.free_space = buffer.capacity() - buffer.size();  // Remaining capacity

    return info;
}
```

The key points:
- Use `hexi::buffer_adaptor` to interface with the buffer
- The adaptor manages read/write offsets internally
- `readable_size` comes from the adaptor's `size()` method
- `free_space` is calculated from the vector's capacity vs current size

