DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Preview the first byte (data_type) without advancing read pointer
    if (stream.remaining() < 1) {
        throw std::runtime_error("Not enough data to read data_type");
    }

    // Peek at the data_type without consuming it
    result.data_type = stream.peek<uint8_t>();

    // Check if we have enough data for the complete structure
    if (stream.remaining() < sizeof(uint8_t) + sizeof(uint32_t)) {
        throw std::runtime_error("Not enough data for header");
    }

    // Now read the actual data (this will advance the pointer)
    stream >> result.data_type;

    uint32_t item_count;
    stream >> item_count;

    // Calculate required size based on data type
    size_t required_size = sizeof(uint8_t) + sizeof(uint32_t);
    if (result.data_type == 0) { // integers
        required_size += item_count * sizeof(uint32_t);
    } else if (result.data_type == 1) { // floats
        required_size += item_count * sizeof(float);
    } else {
        throw std::runtime_error("Invalid data_type");
    }

    // Check if buffer has enough data for all items
    if (buffer.size() < required_size) {
        throw std::runtime_error("Not enough data for all items");
    }

    // Read items based on data type
    if (result.data_type == 0) {
        // Read integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.int_items[i];
        }
    } else if (result.data_type == 1) {
        // Read floats
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.float_items[i];
        }
    }

    return result;
}
