```cpp
#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <vector>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    using namespace hexi;

    // Create a block allocator that manages blocks of uint32_t
    block_allocator<uint32_t, element_count> allocator;

    std::cout << "=== Block Allocator Free List Demonstration ===\n";
    std::cout << "Element count: " << element_count << "\n";
    std::cout << "Block size: " << sizeof(uint32_t) << " bytes\n\n";

    // Vector to track allocated blocks
    std::vector<uint32_t*> allocated_blocks;

    // Phase 1: Allocate all available blocks
    std::cout << "Phase 1: Allocating all " << element_count << " blocks...\n";
    for (size_t i = 0; i < element_count; ++i) {
        uint32_t* block = allocator.allocate();
        if (block) {
            *block = static_cast<uint32_t>(i + 1); // Store some data
            allocated_blocks.push_back(block);
            std::cout << "Allocated block " << i << " at address: " << block 
                      << " (value: " << *block << ")\n";
        }
    }

    // Phase 2: Deallocate some blocks in specific order to observe free list behavior
    std::cout << "\nPhase 2: Deallocating blocks to build free list...\n";

    // Deallocate blocks 2, 4, 6 first (even indices from our perspective)
    std::vector<uint32_t*> deallocated_first;
    for (size_t i = 2; i < allocated_blocks.size(); i += 2) {
        if (i < allocated_blocks.size()) {
            deallocated_first.push_back(allocated_blocks[i]);
            std::cout << "Deallocating block at: " << allocated_blocks[i] 
                      << " (was value: " << *allocated_blocks[i] << ")\n";
            allocator.deallocate(allocated_blocks[i]);
            allocated_blocks[i] = nullptr;
        }
    }

    // Phase 3: Allocate new blocks - these should come from the free list
    std::cout << "\nPhase 3: Allocating new blocks (should come from free list)...\n";
    for (size_t i = 0; i < 3; ++i) {
        uint32_t* new_block = allocator.allocate();
        if (new_block) {
            *new_block = static_cast<uint32_t>(100 + i); // Different values
            // Check if this block was previously deallocated (LIFO behavior)
            bool from_free_list = false;
            for (auto* old_block : deallocated_first) {
                if (new_block == old_block) {
                    from_free_list = true;
                    break;
                }
            }

            std::cout << "Allocated block at: " << new_block 
                      << " (value: " << *new_block << ") "
                      << (from_free_list ? "[FROM FREE LIST]" : "[NEW BLOCK]") << "\n";

            allocated_blocks.push_back(new_block);
        }
    }

    // Phase 4: Demonstrate LIFO behavior more clearly
    std::cout << "\nPhase 4: Demonstrating LIFO behavior...\n";

    // Clear and start fresh
    for (auto* block : allocated_blocks) {
        if (block) allocator.deallocate(block);
    }
    allocated_blocks.clear();

    // Allocate 3 blocks
    uint32_t* block1 = allocator.allocate();
    uint32_t* block2 = allocator.allocate();  
    uint32_t* block3 = allocator.allocate();

    *block1 = 1; *block2 = 2; *block3 = 3;

    std::cout << "Allocated in order: " << block1 << "(1), " << block2 << "(2), " << block3 << "(3)\n";

    // Deallocate in order 1, 2, 3
    allocator.deallocate(block1);
    allocator.deallocate(block2); 
    allocator.deallocate(block3);
    std::cout << "Deallocated in order: 1, 2, 3\n";

    // Reallocate - should get them back in reverse order (3, 2, 1) due to LIFO free list
    uint32_t* reblock1 = allocator.allocate();
