    uint32_t value = 0x12345678;

    auto result = convert_endianness<std::endian::native, std::endian::big>(value);
    auto back = convert_endianness<std::endian::big, std::endian::native>(result);

    EXPECT_EQ(value, back);
}

TEST(Endian, ConditionalReverseRuntime) {
    uint32_t value = 0x12345678;

    auto result = convert_endianness_runtime(value, std::endian::native, std::endian::little);
    auto back = convert_endianness_runtime(result, std::endian::little, std::endian::native);

    EXPECT_EQ(value, back);
}

TEST(Endian, ConditionalReverseSameEndian) {
    uint32_t value = 0x12345678;

    // Should not change if from == to
    auto result = convert_endianness<std::endian::native, std::endian::native>(value);
    EXPECT_EQ(value, result);
}

