std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Create a file_buffer for reading
    hexi::file_buffer buffer(file_path);

    // Check if the file exists and is readable
    if (buffer.empty()) {
        return {}; // Return empty vector if file can't be opened
    }

    // Determine how many bytes we can actually read
    size_t available_bytes = buffer.size();
    size_t bytes_to_read_actual = (bytes_to_read > available_bytes) ? available_bytes : bytes_to_read;

    // Create destination vector and read data
    std::vector<uint8_t> data(bytes_to_read_actual);
    buffer.read(data.data(), bytes_to_read_actual);

    return data;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Create a file_buffer for reading
    hexi::file_buffer buffer(file_path);

    // Check if the file exists and is readable
    if (buffer.empty()) {
        return {}; // Return empty vector if file can't be opened
    }

    // Determine how many bytes we can actually preview
    size_t available_bytes = buffer.size();
    size_t bytes_to_preview_actual = (bytes_to_preview > available_bytes) ? available_bytes : bytes_to_preview;

    // Create destination vector and copy data (preview without advancing read pointer)
    std::vector<uint8_t> data(bytes_to_preview_actual);
    buffer.copy(data.data(), bytes_to_preview_actual);

    return data;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Create a file_buffer for writing
    // Note: The exact write mode might depend on Hexi's file_buffer implementation
    // This assumes the constructor handles file creation/truncation appropriately
    hexi::file_buffer buffer(file_path);

    // Write the data to the file
    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Create a file_buffer for reading
    hexi::file_buffer buffer(file_path);

    // Return the size of readable data
    return buffer.size();
}
