```cpp
#include <hexi.h>
#include <cstdint>
#include <filesystem>
#include <stdexcept>

uint32_t read_uint32_from_file(const std::filesystem::path& file_path) {
    hexi::file_buffer buffer(file_path.string().c_str());

    // Check if file was opened successfully
    if (!buffer) {
        throw std::runtime_error("Failed to open file for reading: " + file_path.string());
    }

    hexi::binary_stream stream(buffer);
    uint32_t value = 0;
    stream >> value;

    // Check if read was successful
    if (!stream) {
        throw std::runtime_error("Failed to read uint32 from file: " + file_path.string());
    }

    return value;
}

void write_uint32_to_file(const std::filesystem::path& file_path, uint32_t value) {
    hexi::file_buffer buffer(file_path.string().c_str());

    // Check if file was opened successfully
    if (!buffer) {
        throw std::runtime_error("Failed to open file for writing: " + file_path.string());
    }

    hexi::binary_stream stream(buffer);
    stream << value;

    // Check if write was successful
    if (!stream) {
        throw std::runtime_error("Failed to write uint32 to file: " + file_path.string());
    }
}
```

