std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a file buffer for the specified file
    hexi::file_buffer file(file_path);

    // Check if file was opened successfully
    if (!file) {
        return {}; // Return empty vector if file couldn't be opened
    }

    // Create destination buffer
    std::vector<uint8_t> header_data(header_size);

    // Store current position before reading
    auto current_pos = file.tellg();

    // Read the header data
