    // we'll read the data and create a new file buffer for actual reading
    // This approach reads the header but doesn't affect any external file pointer

    // Read data directly into vector
    for (size_t i = 0; i < header_size; ++i) {
        char byte;
        if (file.read(&byte, 1) == 1) {
            header_data.push_back(static_cast<uint8_t>(byte));
