```cpp
#include <hexi/file_buffer.h>
#include <cstdint>
#include <filesystem>
#include <stdexcept>

int32_t read_int32_from_file(const std::filesystem::path& file_path) {
    // Create a file buffer for reading
    hexi::file_buffer buffer(file_path.string().c_str());

    // Create a binary stream from the buffer
    hexi::binary_stream stream(buffer);

    // Read the int32_t value
    int32_t value;
    stream >> value;

    // Check if read was successful
    if (!stream) {
        throw std::runtime_error("Failed to read int32 from file: " + file_path.string());
    }

    return value;
}

float read_float_from_file(const std::filesystem::path& file_path) {
    // Create a file buffer for reading
    hexi::file_buffer buffer(file_path.string().c_str());

    // Create a binary stream from the buffer
    hexi::binary_stream stream(buffer);

    // Read the float value
    float value;
    stream >> value;

    // Check if read was successful
    if (!stream) {
        throw std::runtime_error("Failed to read float from file: " + file_path.string());
    }

    return value;
}
```

