    BufferInfo<> info;

    // Total capacity is the template parameter size
    info.capacity = 1024;

    // For a ring buffer, current size is typically (write_ - read_) modulo capacity
    // But since the static_buffer likely handles this internally, we can use:
    info.current_size = buffer.write_offset - buffer.read_offset;

    // Free space is the remaining capacity
    info.free_space = info.capacity - info.current_size;

