    MockBuffer buffer(50, false);
    hexi::pmc::stream_base stream(buffer);

    auto info = get_stream_state_info(stream);

    EXPECT_EQ(hexi::stream_state::ok, info.state);
    EXPECT_EQ(50, info.buffer_size);
    EXPECT_FALSE(info.is_empty);
