    // Read the length of the string first
    uint32_t length = reader.read_uint32();

    // Create a string with the appropriate size
    std::string str(length, '\0');

    // Read the string data if there's any content
    if (length > 0) {
        reader.read_bytes(&str[0], length);
    }

    return str;
}
