```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

void write_data_to_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t value, const void* data, std::size_t length) {
    // Write the integer value first
    buffer.write(&value, sizeof(value));

    // Then write the byte array
    if (data != nullptr && length > 0) {
        buffer.write(data, length);
    }
}

void read_data_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t& value, void* data, std::size_t length) {
    // Read the integer value first
    buffer.read(&value, sizeof(value));

    // Then read the byte array
    if (data != nullptr && length > 0) {
        buffer.read(data, length);
    }
}

struct BufferInfo {
    std::size_t size;
    std::size_t free_space;
};

BufferInfo get_buffer_info(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    BufferInfo info;
    info.size = buffer.size();

    // For vector-based buffer_adaptor, free space can be calculated as capacity - size
    // This assumes the underlying vector's capacity represents the total available space
    info.free_space = buffer.capacity() - buffer.size();

    return info;
}
```

The implementation follows the Hexi library's buffer interface pattern:

1. **write_data_to_buffer**: Uses the `write()` method to sequentially write the integer value followed by the byte array data to the buffer.

2. **read_data_from_buffer**: Uses the `read()` method to sequentially read the integer value followed by the byte array data from the buffer.

3. **get_buffer_info**: Returns a struct containing:
   - `size`: Current number of bytes in the buffer (obtained via `buffer.size()`)
   - `free_space`: Available space calculated as the difference between capacity and current size

The code includes proper null and length checks for the data parameters to ensure safe operation.

