#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Handle the case where value is 0
    if (value == 0) {
        writer.write_byte(0);
        return 1;
    }

    // Encode the value using varint encoding
    while (value > 0) {
        // Take 7 bits of the value
        uint8_t byte = value & 0x7F;
        value >>= 7;

        // If there are more bytes to follow, set the high bit
        if (value > 0) {
            byte |= 0x80;
        }

        writer.write_byte(byte);
        bytes_written++;

        // Check if stream is still in good state
        if (writer.state() != hexi::stream_state::ok) {
            break;
        }
    }

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    T result = 0;
    int shift = 0;

    while (true) {
        // Read a byte from the stream
        uint8_t byte = reader.read_byte();

        // Check if stream is in good state
        if (reader.state() != hexi::stream_state::ok) {
            break;
        }

        // Add the 7 bits to the result
        result |= static_cast<T>(byte & 0x7F) << shift;
        shift += 7;

        // If high bit is not set, this is the last byte
        if ((byte & 0x80) == 0) {
            break;
        }

        // Safety check to avoid infinite loops with malformed data
        if (shift >= (int)(sizeof(T) * 8)) {
            // Set error state if we've shifted more than the type can hold
            reader.set_state(hexi::stream_state::read_err);
            break;
        }
    }

    return result;
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Create a writer and encode the value
    hexi::pmc::binary_stream_writer writer(adaptor);
    encode_varint<T>(writer, original_value);

    // Check if encoding was successful
    if (writer.state() != hexi::stream_state::ok) {
        return false;
    }

    // Create a reader and decode the value
    hexi::pmc::buffer_adaptor read_adaptor(buffer);
    hexi::pmc::binary_stream_reader reader(read_adaptor);
    T decoded_value = decode_varint<T>(reader);

    // Check if decoding was successful
    if (reader.state() != hexi::stream_state::ok) {
        return false;
    }

    // Compare the original and decoded values
    return original_value == decoded_value;
}
