```cpp
#include <hexi/exception.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

struct UnderrunInfo {
    std::size_t read_size;
    std::size_t total_read;
    std::size_t buff_size;
    bool occurred;
};

UnderrunInfo catch_buffer_underrun() {
    try {
        throw; // Re-throw the current exception to catch it
    } catch (const hexi::buffer_underrun& e) {
        return UnderrunInfo{e.read_size, e.total_read, e.buff_size, true};
    } catch (...) {
        // Not a buffer_underrun exception
        return UnderrunInfo{0, 0, 0, false};
    }
}

UnderrunInfo safe_read_with_underrun_check(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, void* destination, std::size_t length) {
    try {
        buffer.read(destination, length);
        return UnderrunInfo{0, 0, 0, false}; // No underrun occurred
    } catch (const hexi::buffer_underrun& e) {
        // Extract information directly from the caught exception
        return UnderrunInfo{e.read_size, e.total_read, e.buff_size, true};
    } catch (...) {
        // Some other exception occurred
        return UnderrunInfo{0, 0, 0, false};
    }
}
```

