        info.occurred = false;
    } catch (const hexi::stream_read_limit& e) {
        // Catch the stream_read_limit exception and extract information
        info.read_size = e.read_size;
        info.total_read = e.total_read;
        info.read_limit = e.read_limit;
        info.occurred = true;
    } catch (...) {
        // Handle other exceptions if needed
        // For this function, we only care about stream_read_limit
        info.occurred = false;
    }

    return info;
}

