    EXPECT_EQ(1, obj1->id);
    EXPECT_EQ(2, obj2->id);
    EXPECT_EQ(3, obj3->id);
    EXPECT_DOUBLE_EQ(10.5, obj1->value);
    EXPECT_DOUBLE_EQ(20.5, obj2->value);
    EXPECT_DOUBLE_EQ(30.5, obj3->value);

    // Deallocate in reverse order (LIFO) - push() is called internally
    allocator.deallocate(obj3);
    allocator.deallocate(obj2);
    allocator.deallocate(obj1);
}

TEST(BlockAllocator, LIFOBehavior) {
    hexi::block_allocator<PoolObject, 10> allocator;

    // Allocate objects - pop() is called internally
    auto* obj1 = allocator.allocate(1, 1.0);
    auto* obj2 = allocator.allocate(2, 2.0);
    auto* obj3 = allocator.allocate(3, 3.0);

    // Deallocate in reverse order - push() is called internally
    allocator.deallocate(obj3);
    allocator.deallocate(obj2);
    allocator.deallocate(obj1);

    // Allocate again - should reuse blocks in LIFO order (last deallocated first)
    auto* obj4 = allocator.allocate(4, 4.0);
    auto* obj5 = allocator.allocate(5, 5.0);
    auto* obj6 = allocator.allocate(6, 6.0);

    // Verify the objects are valid
    EXPECT_EQ(4, obj4->id);
    EXPECT_EQ(5, obj5->id);
    EXPECT_EQ(6, obj6->id);
    EXPECT_DOUBLE_EQ(4.0, obj4->value);
    EXPECT_DOUBLE_EQ(5.0, obj5->value);
    EXPECT_DOUBLE_EQ(6.0, obj6->value);

    allocator.deallocate(obj6);
    allocator.deallocate(obj5);
    allocator.deallocate(obj4);
}

TEST(BlockAllocator, MultipleAllocations) {
    hexi::block_allocator<PoolObject, 5> allocator;
    std::vector<PoolObject*> objects;

    // Allocate up to capacity - each allocate() internally calls pop()
    for (int i = 0; i < 5; ++i) {
        objects.push_back(allocator.allocate(i, i * 10.0));
    }

    // Verify all allocations succeeded
    for (int i = 0; i < 5; ++i) {
        EXPECT_EQ(i, objects[i]->id);
        EXPECT_DOUBLE_EQ(i * 10.0, objects[i]->value);
    }

    // Deallocate all - each deallocate() internally calls push()
    for (auto* obj : objects) {
        allocator.deallocate(obj);
    }
}

