```cpp
#include <hexi/pmc/buffer_base.h>
#include <vector>
#include <cstddef>
#include <algorithm>

class CustomBuffer : public hexi::pmc::buffer_base {
    std::vector<std::byte> data_;
    std::size_t read_pos_ = 0;
    std::size_t write_pos_ = 0;

public:
    using value_type = std::byte;
    using size_type = std::size_t;

    // Required buffer_base methods
    size_type size() const override {
        return data_.size();
    }

    [[nodiscard]] bool empty() const override {
        return data_.empty();
    }

    // buffer_read interface methods
    void read(void* destination, size_type length) override {
        if (read_pos_ + length > data_.size()) {
            // Handle read beyond buffer - you might want to throw an exception
            return;
        }

        std::byte* dest_bytes = static_cast<std::byte*>(destination);
        std::copy(data_.begin() + read_pos_, data_.begin() + read_pos_ + length, dest_bytes);
        read_pos_ += length;
    }

    void copy(void* destination, size_type length) const override {
        if (read_pos_ + length > data_.size()) {
            // Handle copy beyond buffer - you might want to throw an exception
            return;
        }

        std::byte* dest_bytes = static_cast<std::byte*>(destination);
        std::copy(data_.begin() + read_pos_, data_.begin() + read_pos_ + length, dest_bytes);
    }

    void skip(size_type length) override {
        read_pos_ = std::min(read_pos_ + length, data_.size());
    }

    const std::byte& operator[](const size_type index) const override {
        return data_.at(index);
    }

    std::size_t find_first_of(std::byte val) const override {
        auto it = std::find(data_.begin(), data_.end(), val);
        if (it != data_.end()) {
            return std::distance(data_.begin(), it);
        }
        return npos; // Use the static npos from buffer_read
    }

    // buffer_write interface methods
    void write(const void* source, size_type length) override {
        const std::byte* src_bytes = static_cast<const std::byte*>(source);

        // If writing beyond current size, resize the vector
        if (write_pos_ + length > data_.size()) {
            data_.resize(write_pos_ + length);
        }

        std::copy(src_bytes, src_bytes + length, data_.begin() + write_pos_);
        write_pos_ += length;
    }

    void reserve(size_type length) override {
        data_.reserve(length);
    }

    bool can_write_seek() const override {
        return true;
    }

    void write_seek(buffer_seek direction, std::size_t offset) override {
        switch (direction) {
            case buffer_seek::begin:
                write_pos_ = offset;
                break;
            case buffer_seek::current:
                write_pos_ += offset;
                break;
            case buffer_seek::end:
                write_pos_ = data_.size() + offset;
                break;
        }

        // Clamp to valid range
        if (write_pos_ > data_.size()) {
            write_pos_ = data_.size();
        }
    }

    // buffer interface methods (combining read and write)
    std::byte& operator[](const std::size_t index) override {
        return data_.at(index);
    }

    // Helper method to add data (for testing)
    void add_data(const void* source, std::size_t length) {
        const std::byte* bytes = static_cast<const std::byte*>(source);
        data_.insert(data_.end(), bytes, bytes + length);
        write_pos_ = data_.size(); // Update write position
    }

    // Helper method to clear data (for testing)
    void clear() {
        data_.clear();
        read_pos_ = 0;
        write_pos_ = 0;
    }

    // Additional helper methods
    std::size_t get_read_position() const { return read_pos_; }
    std::size_t get_write_position() const { return write_pos_; }
    void set_read_position(std::size_t pos) { read_pos_ = std::min(pos, data_.size()); }
    void set_write_position(std::size_t pos) { write_pos_ = std::min(pos, data_.size()); }

    // Get direct access to underlying data (for advanced use cases)
    const std::vector<std::byte>& get_data() const { return data_; }
    std::vector<std::byte>& get_data() { return data_; }
};
```

This implementation provides:

1. **Required `buffer_base` methods**: `size()` and `empty()`
2. **`buffer_read` interface**: `read()`, `copy()`, `skip()`, `operator[] const`, and `find_first_of()`
3. **`buffer_write` interface**: `write()`, `reserve()`, `can_write_seek()`, and `write_seek()`
4. **Full `buffer` interface**: non-const `operator[]`
5. **Position tracking**: Separate read and write positions
6. **Bounds checking**: Using `std::vector::at()` for safe access
7. **Additional utilities**: Position getters/setters and direct data access

The implementation uses `std::vector<std::byte>` as the underlying storage and maintains separate read/write positions for stream-like operations.

