#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring> // for memcpy
#include <stdexcept>

struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor for the input buffer
    hexi::pmc::buffer_adaptor adaptor(const_cast<std::vector<uint8_t>&>(buffer));

    // Check if we have enough data for the header
    if (adaptor.size() < sizeof(Header)) {
        throw std::runtime_error("Buffer too small for header");
    }

    // Use copy() to peek at header without advancing read cursor
    std::array<std::byte, sizeof(Header)> header_data;
    adaptor.copy(header_data.data(), sizeof(Header));

    // Use read_ptr() to verify pointer position hasn't changed
    const std::byte* current_ptr = adaptor.read_ptr();
    if (current_ptr != reinterpret_cast<const std::byte*>(buffer.data())) {
        throw std::runtime_error("Read pointer advanced during peek");
    }

    // Convert the copied data to Header structure
    Header header;
    std::memcpy(&header, header_data.data(), sizeof(Header));

    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor for the input buffer
    hexi::pmc::buffer_adaptor adaptor(const_cast<std::vector<uint8_t>&>(buffer));

    std::vector<uint8_t> result;

    // Check if we have at least 1 byte to peek at
    if (adaptor.size() < 1) {
        return result; // Return empty vector
    }

    // Use copy() to peek at first byte
    std::byte first_byte;
    adaptor.copy(&first_byte, 1);

    // Condition: if first byte is non-zero, read more data
    if (first_byte != std::byte{0}) {
        // Based on the peeked value, decide to read more data
        // For example, if first byte indicates data length, read that much
        uint8_t data_length = static_cast<uint8_t>(first_byte);

        // Make sure we have enough data to read
        if (adaptor.size() >= data_length) {
            result.resize(data_length);
            // Use read() to consume data
            adaptor.read(reinterpret_cast<std::byte*>(result.data()), data_length);
        }
    }

    return result;
}
