#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <span>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& stream) const {
        // Write sensor_id directly
        stream(sensor_id);

        // Convert and write temperatures (native to little-endian)
        for (const auto& temp : temperatures) {
            float temp_le = hexi::endian::conditional_reverse(temp, std::endian::native, std::endian::little);
            stream(temp_le);
        }

        // Convert and write pressure (native to little-endian)
        double pressure_le = hexi::endian::conditional_reverse(pressure, std::endian::native, std::endian::little);
        stream(pressure_le);
    }

    void serialise(auto& stream) {
        // Read sensor_id directly
        stream(sensor_id);

        // Read and convert temperatures (little-endian to native)
        for (auto& temp : temperatures) {
            stream(temp);
            hexi::endian::little_to_native_inplace(temp);
        }

        // Read and convert pressure (little-endian to native)
        stream(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    data.serialise(stream);
    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    MeasurementData data;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    data.serialise(stream);
    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    SensorInfo info;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Extract null-terminated sensor name if present
    info.sensor_name = stream.view();

    // Check bounds before reading sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    stream(info.sensor_id);

    // Skip remaining data
    stream.skip(buffer.size() - adaptor.read_position());

    return info;
}
